\subsection{The pushout-of-free-sheaves analog}

\begin{lemma}[Pushout of free $\ModuleCat\,k$-sheaves under a Mayer-Vietoris square (iter-019)]
  \label{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
  \lean{AlgebraicGeometry.Scheme.HModule'_isPushoutModuleCatFreeSheaf}
  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
  Let $k$ be a field, $C$ a category with $J : \mathrm{GrothendieckTopology}\,C$, and assume $\HasWeakSheafify\,J\,(\mathrm{Type}\,u)$ and $\HasSheafify\,J\,(\ModuleCat.\{u\}\,k)$. Let $S : J.\MayerVietorisSquare$. Then the image of $S$ under the composite
  \[
    \yoneda \;\circ\; \Functor.\whiskeringRight\,(\ModuleCat.\free\,k) \;\circ\; \presheafToSheaf\,J\,\_
  \]
  is a pushout square in $\Sheaf\,J\,(\ModuleCat\,k)$.
\end{lemma}

\begin{proof}
  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
  Direct mirror of Mathlib's $\mathtt{GrothendieckTopology.MayerVietorisSquare.isPushoutAddCommGrpFreeSheaf}$ (\texttt{MayerVietorisSquare.lean} L154--160) with $\AddCommGrpCat.\free \rightarrow \ModuleCat.\free\,k$. The proof reads as: (1) start with $S.\isPushout$, the type-level pushout; (2) push it through $\Sheaf.\composeAndSheafify\,J\,(\ModuleCat.\free\,k)$ (which preserves pushouts because $\ModuleCat.\free\,k$ is a left adjoint, registered by Definition~\ref{def:Scheme_ModuleCat_free_isLeftAdjoint}); (3) translate the resulting square's shape via the canonical iso $\presheafToSheaf\composeAndSheafify\mathrm{Iso}$ between two ways of writing $\presheafToSheaf\,J\,\_ \circ (\yoneda \circ \mathrm{whiskerRight}\,\free)$. Body:
  \begin{lstlisting}
  (S.isPushout.map (Sheaf.composeAndSheafify J (ModuleCat.free k))).of_iso
    ((Square.mapFunctor.mapIso
      (presheafToSheafCompComposeAndSheafifyIso J (ModuleCat.free k))).app
        (S.map yoneda))
  \end{lstlisting}
  Plan-agent \texttt{lean\_run\_code} probe (iter-019) confirms the body typechecks end-to-end against current Mathlib + post-iter-018 project state, kernel-only axioms (\lstinline{propext}, \lstinline{Classical.choice}, \lstinline{Quot.sound}). Every component (\lstinline{Sheaf.composeAndSheafify}, \lstinline{Square.IsPushout.map}, \lstinline{Square.IsPushout.of_iso}, \lstinline{presheafToSheafCompComposeAndSheafifyIso}, \lstinline{Square.mapFunctor.mapIso}) is value-category-agnostic in Mathlib; the proof transfers cleanly.
\end{proof}

\subsection{The short-complex carrier}

\begin{definition}[Short complex of free $\ModuleCat\,k$-sheaves (iter-019)]
  \label{def:Scheme_HModule_prime_shortComplex}
  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex}
  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
  In the setting of Lemma~\ref{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}, define the short complex of $\Sheaf\,J\,(\ModuleCat\,k)$:
  \[
    (\presheafToSheaf\,J\,\_)\,(\yoneda\,S.X_1 \circ \ModuleCat.\free\,k)
    \xrightarrow{\;f\;}
    (\presheafToSheaf\,J\,\_)\,(\yoneda\,S.X_2 \circ \ModuleCat.\free\,k) \boxplus (\presheafToSheaf\,J\,\_)\,(\yoneda\,S.X_3 \circ \ModuleCat.\free\,k)
    \xrightarrow{\;g\;}
    (\presheafToSheaf\,J\,\_)\,(\yoneda\,S.X_4 \circ \ModuleCat.\free\,k)
  \]
  where $f$ is the biproduct lift of the pair $(\presheafToSheaf\,(\mathrm{whiskerRight}\,(\yoneda.\mathrm{map}\,S.f_{1,2})), -\presheafToSheaf\,(\mathrm{whiskerRight}\,(\yoneda.\mathrm{map}\,S.f_{1,3})))$ and $g$ is the biproduct desc of the pair $(\presheafToSheaf\,(\mathrm{whiskerRight}\,(\yoneda.\mathrm{map}\,S.f_{2,4})), \presheafToSheaf\,(\mathrm{whiskerRight}\,(\yoneda.\mathrm{map}\,S.f_{3,4})))$. The composition-zero relation $f \circ g = 0$ follows from the cokernel-cofork condition of the pushout in Lemma~\ref{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}.
\end{definition}

\begin{proof}
  \uses{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
